# Category: serverless_security

import json
import logging
import os
from datetime import datetime, timezone
from typing import Any, Dict, List

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent


app = func.FunctionApp()

STORAGE_ACCOUNT_URL = os.environ["STORAGE_ACCOUNT_URL"]
INPUT_CONTAINER = os.environ.get("INPUT_CONTAINER", "input")
COSMOS_ACCOUNT_URI = os.environ["COSMOS_ACCOUNT_URI"]
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvpdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]

credential = DefaultAzureCredential()

blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ACCOUNT_URI, credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
container = database.create_container_if_not_exists(
    id=COSMOS_CONTAINER_NAME,
    partition_key=PartitionKey(path="/partitionKey"),
)


def process_blob_content(blob_name: str, content: bytes) -> Dict[str, Any]:
    text = content.decode("utf-8", errors="replace")
    lines = [line for line in text.splitlines() if line.strip()]
    words = text.split()
    return {
        "blobName": blob_name,
        "sizeBytes": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "processedAt": datetime.now(timezone.utc).isoformat(),
        "preview": text[:500],
    }


def write_result_to_cosmos(result: Dict[str, Any]) -> Dict[str, Any]:
    item = {
        "id": f"{result['blobName']}:{result['processedAt']}",
        "partitionKey": result["blobName"],
        "result": result,
        "type": "blob-processing-result",
    }
    return container.upsert_item(item)


def publish_notification(result_item: Dict[str, Any]) -> None:
    event = EventGridEvent(
        subject=f"/blobProcessing/{result_item['partitionKey']}",
        event_type="Blob.Processed",
        data_version="1.0",
        data={
            "id": result_item["id"],
            "blobName": result_item["partitionKey"],
            "processedAt": result_item["result"]["processedAt"],
            "metrics": {
                "sizeBytes": result_item["result"]["sizeBytes"],
                "lineCount": result_item["result"]["lineCount"],
                "wordCount": result_item["result"]["wordCount"],
            },
        },
    )
    event_grid_client.send([event])


def list_target_blobs(container_name: str) -> List[str]:
    container_client = blob_service_client.get_container_client(container_name)
    return [blob.name for blob in container_client.list_blobs()]


@app.function_name(name="ProcessBlobs")
@app.route(route="process-blobs", methods=["POST"])
def process_blobs(req: func.HttpRequest) -> func.HttpResponse:
    logging.info("Starting blob processing run")

    try:
        body = req.get_json()
    except ValueError:
        body = {}

    container_name = body.get("container", INPUT_CONTAINER)
    explicit_blobs = body.get("blobs")

    try:
        container_client = blob_service_client.get_container_client(container_name)
        blob_names = explicit_blobs or list_target_blobs(container_name)
        processed = []

        for blob_name in blob_names:
            blob_client = container_client.get_blob_client(blob_name)
            content = blob_client.download_blob().readall()
            result = process_blob_content(blob_name, content)
            cosmos_item = write_result_to_cosmos(result)
            publish_notification(cosmos_item)
            processed.append(
                {
                    "blobName": blob_name,
                    "cosmosId": cosmos_item["id"],
                    "processedAt": result["processedAt"],
                }
            )

        return func.HttpResponse(
            json.dumps(
                {
                    "status": "success",
                    "container": container_name,
                    "processedCount": len(processed),
                    "items": processed,
                }
            ),
            status_code=200,
            mimetype="application/json",
        )
    except Exception as exc:
        logging.exception("Processing failed")
        return func.HttpResponse(
            json.dumps({"status": "error", "message": str(exc)}),
            status_code=500,
            mimetype="application/json",
        )